/* =========================================================================
   ATLAS Utility Web — tools/rfq_template.js
   Base64 (UTF-8) of the desktop templates/rfq_template_clean.html.
   Embedded verbatim so the RFQ tool can fill it entirely in the browser,
   exactly as the IPC/SLI/PL tools embed their .xlsx templates. The original
   markup (Word/Outlook-flavored HTML with mso conditional blocks) is kept
   byte-for-byte so the pasted email matches the desktop utility.
   ========================================================================= */

const RFQ_TEMPLATE_B64 = "";

/** Decode the embedded base64 to a UTF-8 string (handles ✅, en-dashes, etc.). */
function rfqTemplateHtml() {
  const bin = atob(RFQ_TEMPLATE_B64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return new TextDecoder("utf-8").decode(bytes);
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = { RFQ_TEMPLATE_B64, rfqTemplateHtml };
}
